#include <stdio.h>
#include <string.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        char s[100001];
        scanf("%s", s);
        int n = strlen(s);
        int i = 0, j = n - 1;
        while (i < j && s[i] == s[j]) {
            i++;
            j--;
        }
        printf("%d\n", i);
    }
    return 0;
}

